class Solution {
    public String licenseKeyFormatting(String s, int k) {
        // Remove dashes and convert to uppercase
        StringBuilder sb = new StringBuilder();
        for (char c : s.toCharArray()) {
            if (c != '-') {
                sb.append(Character.toUpperCase(c));
            }
        }

        // Calculate the length of the first group
        int n = sb.length();
        int firstGroupLength = n % k;
        if (firstGroupLength == 0) {
            firstGroupLength = k;
        }

        // Build the result
        StringBuilder result = new StringBuilder();
        if (firstGroupLength != k) {
            result.append(sb.substring(0, firstGroupLength));
        }
        for (int i = firstGroupLength; i < n; i += k) {
            result.append(sb.substring(i, i + k)).append("-");
        }

        // Remove the trailing dash
        return result.toString().replaceAll("-$", "");
    }
}
```
